def make_parsers():
    """
    Crea un analizador de nivel superior y sus subanalizadores, y devuélvalos como una tupla.
    """
    class HighLevelParser:
        def parse(self, data):
            # Implementación del análisis de nivel superior
            return f"HighLevelParser: {data}"

    class SubParserA:
        def parse(self, data):
            # Implementación del análisis para SubParserA
            return f"SubParserA: {data}"

    class SubParserB:
        def parse(self, data):
            # Implementación del análisis para SubParserB
            return f"SubParserB: {data}"

    high_level_parser = HighLevelParser()
    sub_parser_a = SubParserA()
    sub_parser_b = SubParserB()

    return (high_level_parser, sub_parser_a, sub_parser_b)

def deep_merge_nodes(nodes):
    from ruamel.yaml.nodes import ScalarNode, MappingNode

    merged = {}

    for key_node, value_node in nodes:
        key = key_node.value

        if key not in merged:
            merged[key] = value_node
        else:
            existing_value = merged[key]
            if isinstance(existing_value, MappingNode) and isinstance(value_node, MappingNode):
                # Merge the two MappingNodes
                for sub_key_node, sub_value_node in value_node.value:
                    existing_value.value.append((sub_key_node, sub_value_node))
            else:
                # If there's a conflict with non-MappingNode, take the last one
                merged[key] = value_node

    # Convert merged dictionary back to the required format
    result = []
    for key, value in merged.items():
        result.append((ScalarNode(tag='tag:yaml.org,2002:str', value=key), value))

    return result

