from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    if number < 0:
        raise ValueError("Number must be non-negative")

    base = len(alphabet)
    if base < 2:
        raise ValueError("Alphabet must have at least two characters")

    if number == 0:
        result = alphabet[0]
    else:
        result = ""
        while number > 0:
            result = alphabet[number % base] + result
            number //= base

    if padding is not None:
        result = result.rjust(padding, alphabet[0])

    return result

def replace_dots(value, arg):  
    """
    Reemplaza todos los valores de '.' por el argumento proporcionado en la cadena dada.  
    """
    return value.replace('.', arg)

def unquote(name):
    """
    Eliminar comillas del nombre dado.
    """
    return name.replace('"', '').replace("'", "")

import re

def get_pattern(pattern, strip=True):
    """
    Este método convierte la cadena proporcionada en un objeto de patrón regex.
    """
    if strip:
        pattern = pattern.strip()
    return re.compile(pattern)

def _dump_string(obj, dumper=None):
    """
    Volcar a una cadena en formato py2-unicode o py3-string
    """
    if dumper is None:
        dumper = str  # Default to str for Python 3
    return dumper(obj)

def force_string(obj):
    """
    Esta función devuelve el objeto de tipo `bytes` correspondiente a ``obj`` en caso de que sea una cadena utilizando UTF-8.
    """
    if isinstance(obj, str):
        return obj.encode('utf-8')
    return obj

def protocol_handlers(cls, protocol_version=None):
    """
    Devuelve un diccionario de los controladores de protocolo Bolt disponibles, indexados por una tupla de versión. Si se proporciona una versión de protocolo explícita, el diccionario contendrá cero o un elemento, dependiendo de si esa versión es compatible. Si no se proporciona ninguna versión de protocolo, se devolverán todas las versiones disponibles.

    :param protocol_version: tupla que identifica una versión específica del protocolo (por ejemplo, (3, 5)) o None
    :return: diccionario que mapea tuplas de versión a clases de controladores para todas las versiones relevantes y compatibles del protocolo
    :raise TypeError: si la versión del protocolo no se pasa como una tupla
    """
    if protocol_version is not None and not isinstance(protocol_version, tuple):
        raise TypeError("La versión del protocolo debe ser una tupla")

    # Simulación de controladores de protocolo disponibles
    available_handlers = {
        (3, 0): "HandlerV3_0",
        (3, 5): "HandlerV3_5",
        (4, 0): "HandlerV4_0",
    }

    if protocol_version is not None:
        return {protocol_version: available_handlers.get(protocol_version)} if protocol_version in available_handlers else {}

    return available_handlers

def _get_seq_with_type(seq, bufsize=None):
    """
    Devuelve un par (secuencia, tipo).
    La secuencia se deriva de *seq*
    (o es *seq*, si este es de un tipo de secuencia).
    """
    if isinstance(seq, (list, tuple, set, str)):
        return seq, type(seq)
    else:
        return (seq,), type(seq)

def verifyClass(iface, candidate, tentative=False):
    """
    Verifica que el *candidate* pueda proporcionar correctamente *iface*.
    """
    if tentative:
        return issubclass(candidate, iface) or (hasattr(candidate, '__bases__') and any(issubclass(base, iface) for base in candidate.__bases__))
    return isinstance(candidate, iface)

def determineMetaclass(bases, explicit_mc=None):
    """
    Determina la metaclase a partir de una o más clases base y un __metaclass__ explícito opcional.
    """
    if explicit_mc is not None:
        return explicit_mc

    metaclasses = [type(base) for base in bases]
    if not metaclasses:
        return type

    metaclass = metaclasses[0]
    for mc in metaclasses[1:]:
        if not issubclass(mc, metaclass):
            metaclass = type('CombinedMeta', (metaclass, mc), {})

    return metaclass

def pop(self, key, default=__marker):
    """
    D.pop(k[,d]) -> v, elimina la clave especificada y devuelve el valor correspondiente.
    Si la clave no se encuentra, se devuelve `d` si se proporciona; de lo contrario, se genera una excepción KeyError.
    """
    if key in self:
        value = self[key]
        del self[key]
        return value
    elif default is not self.__marker:
        return default
    else:
        raise KeyError(f'Key {key} not found.')

